INSERT INTO `devotion_table` (`id_devotion`, `title`, `content`, `id_chapter`) VALUES
(1, 'Penciptaan', 'Pada mulanya...', 1),
(10, '📖 Guidelines: Kej. 3 📖', '* Kedatangan si ular (setan) ke dlm Taman Eden mencobai Adam dan Hawa menjd tantangan bg manusia utk memilih mentaati Allah ataukah memberontak melawan Allah, dan berdampak pd seluruh ciptaan. \r\nAdam memilih utk memberontak berdasarkan kerelaan hatinya dgn mengikuti rayuan setan yg sgt halus tsb, dan mengakibatkan rusaknya ordo penciptaan, rusaknya relasi harmonis yg sebelumnya Allah telah bentuk (ay 16). Dan mrk mulai alami berbagai dosa, penderitaan, dan sakit; termasuk jg kematian fisik dan rohani (ay 17-19).\r\nBagi Allah tindakan Adam dan Hawa ini bukan sekedar persoalan ketidaktaatan semata, tp pengkhianatan, krn mereka lebih memilih utk taat kpd ciptaan Tuhan dr pd taat kpd Tuhan.\r\n\r\n* Alkitab disini sama sekali tdk menyebutkan asal usul dr setan tsb, bgmana ia menjd setan dan kapan itu terjd. Namun dr Kej 1:31 yg mengatakan \"Allah melihat segala yg dijadikanNya sungguh amat baik\", kelihatannya kejatuhan Setan terjd di atara Kej 1:31 dan Kej 3, sebabnya krn Alkitab tdk pernah mengajarkan ada 2 kekuatan baik dan jahat yg seimbang dlm kuasa dan kekal (Masih ingat di refleksi Kej 1 kalau Kejadian menyatakan Allah yg Esa, bukan politeisme).\r\n\r\n* Perhatikan jg jawaban yg diberikan Hawa kpd Setan di ay 2 dan komparasikan dg perkataan Tuhan kpd Adam pd Kej 2:16. Kita dpt temukan adanya penambahan terhadap firman Tuhan dan pengurangan thd firman oleh Adam kpd Hawa.\r\n\r\n*Penambahan:*\r\n- penambahan kata \"raba\"\r\n\r\n*Pengurangan:*\r\n- tidak ada kata \"semua\", \"bebas\"\r\n- kata \"pasti mati\" dikurangi bobotnya menjd \"mati\"\r\n\r\n* Selain dr adanya penambahan dan pengurangan thd firman Tuhan, kelihatannya Hawa jg gagal utk mengidentifikasi pohon pengetahuan baik dan jahat (2:17) dgn hanya berkata \"pohon yg ada ditengah² taman\" (ay 3). Kelihatannya Hawa berprinsip kalau tdk terlalu soal utk \"memodifikasi/mengubah\" perkataan Tuhan.\r\n\r\n* Perkataan siapa yg benar: Allah ataukah Setan? \r\nSeringkali dikatakan perkataan setan yg benar TAPI yg benar adl *separuh kebenaran*:\r\n- Adam tdk lgsung mati, TAPI masih hidup sampai usia 930 tahun baru mati (5:5).\r\n- Mata mereka terbuka, TAPI utk mengetahui kalau mereka telanjang.\r\n- Dan mereka menjd mengerti sesuatu yg sebelumnya mrk tdk mengerti kejahatan melalui pengalaman, TAPI rasa bersalah mrk membuat mereka tdk berani bertemu dgn Tuhan.\r\n\r\n* Akibat dr manusia mendengarkan Iblis, mereka menjd budak kejahatan dan diusir keluar dr Taman Eden, tdk lg boleh makan buah pohon kehidupan, dan ada di bawah kuasa maut. Semua ini bukanlah yg TUHAN kehendaki dr manusia, juga manusia TIDAK DAPAT bersembunyi dr keadilan Allah.\r\n\r\n* Dan keberadaan Adam sbg seorg yg sgt memahami larangan Tuhan tetapi ada disamping Hawa sepanjang pencobaan tsb dan turut memakan buah juga (ay 6), menunjukkan kalau Adam berada dlm kesadaran penuh utk melawan Allah (bdk. 1Tim 2:14). Adam telah gagal utk menjalankan tugasnya sbg yg bertanggung jawab utk memelihara Taman (Kej 2:15) dan juga perempuan yg telah Allah ciptakan sbg penolong bagi dirinya (2:18,20).\r\n\r\n* Setelah kejatuhan, Allah jg masih menyatakan kasihNya dan pemeliharaanNya bagi manusia:\r\n- Kej 3:15 merupakan pemberitaan pertama Injil kpd manusia pertama _(disebut protoevangelium)._\r\n- Kej 3:20-21, Allah membuatkan pakaian dr kulit binatang utk dikenakan manusia (kita jg dpt mengertinya sbg penetapan sistem korban binatang utk menebus dosa dan bahkan merupakan tipologi dr kematian Kristus utk menebus dosa).\r\n\r\n\r\nRenungan:\r\n1. Seberapa ketatkah kita di dlm mempertahankan setiap perkataan Tuhan persis spt yg Tuhan katakan dlm hidup kita, ataukah kita melihatnya sbg perkataan yg boleh dimodifikasi spt Hawa dan Adam? Tahukah kita kalau konsekuensinya adl kecelakaan bagi diri kita dan hukuman dr Allah?\r\n\r\n2. Apa yg kita lihat saat kita mengalami sakit, penderitaan, perselisihan, perlawanan di dlm relasi suami isteri, kecurigaan thd satu dgn yg lain, kesulitan di dlm pekerjaan dan juga sakit bersalin? Apakah kita diingatkan kalau semua itu terjd sbg akibat dosa kita? Jika ya, adakah langkah yg segera kita ambil? Apakah itu?\r\n\r\n3. Dikala sulit, kesalahan dlm pengambilan keputusan bahkan dikala jatuh dlm dosa, apakah kita masih dpt melihat adanya anugerah dan berkat pemeliharaan Allah dlm hidup kita? Bgmana respon kita? Makin menarik diri menjauh dr kasih Tuhan tsb; ataukah makin mendekat kpd anugerah kasih pemeliharaan Tuhan? Terutama penebusan Tuhan Yesus atas dosa?', 3);
